using System.Net.Http.Json;

namespace ShipmentTracker.Client.Services;

public class ClientShipmentService : IShipmentService
{
    private readonly HttpClient _http;

    public ClientShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await _http.GetFromJsonAsync<ShipmentDto?>($"api/shipments/track/{trackingNumber}");
