```csharp
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;
using System.Security.Claims;

namespace ShipmentTracker.Services;

public class ServerShipmentService : IShipmentService
{
    private readonly ApplicationDbContext _db;
    private readonly AuthenticationStateProvider _authStateProvider;

    public ServerShipmentService(ApplicationDbContext db, AuthenticationStateProvider authStateProvider)
    {
        _db = db;
        _authStateProvider = authStateProvider;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await _db.Shipments
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        var authState = await _authStateProvider.GetAuthenticationStateAsync();
        var userId = authState.User.FindFirstValue(ClaimTypes.NameIdentifier);
        return await _db.Shipments
            .Where(s => s.CustomerId == userId)
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentDto dto)
    {
        var authState = await _authStateProvider.GetAuthenticationStateAsync();
        var userId = authState.User.FindFirstValue(ClaimTypes.NameIdentifier);

        var shipment = new Shipment
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = dto.Origin,
            Destination = dto.Destination,
            RecipientName = dto.RecipientName,
            CustomerId = dto.CustomerId,
            DispatcherId = userId,
            Status = ShipmentStatus.Pending,
            CreatedAt = DateTime.UtcNow,
            EstimatedDelivery = dto.EstimatedDelivery
        };

        _db.Shipments.Add(shipment);
        await _db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task UpdateStatusAsync(int id, string status)
    {
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment is not null && Enum.TryParse<ShipmentStatus>(status, out var newStatus))
        {
            shipment.Status = newStatus;
            await _db.SaveChangesAsync();
        }
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status.ToString(),
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        RecipientName = s.RecipientName,
        CustomerId = s.CustomerId
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}
```

### 8. Create API endpoints

Create `ShipmentTracker/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;
using System.Security.Claims;

namespace ShipmentTracker;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status.ToString(),
                    CreatedAt = s.CreatedAt,
                    EstimatedDelivery = s.EstimatedDelivery,
                    RecipientName = s.RecipientName,
                    CustomerId = s.CustomerId
                })
                .ToListAsync();
            return Results.Ok(shipments);
        });

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status.ToString(),
                CreatedAt = shipment.CreatedAt,
                EstimatedDelivery = shipment.EstimatedDelivery,
                RecipientName = shipment.RecipientName,
                CustomerId = shipment.CustomerId
            });
        }).AllowAnonymous();

        group.MapGet("my", async (ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
            var shipments = await db.Shipments
                .Where(s => s.CustomerId == userId)
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status.ToString(),
                    CreatedAt = s.CreatedAt,
                    EstimatedDelivery = s.EstimatedDelivery,
                    RecipientName = s.RecipientName,
                    CustomerId = s.CustomerId
                })
                .ToListAsync();
            return Results.Ok(shipments);
        });

        group.MapPost("", async (CreateShipmentDto dto, ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
            var shipment = new Shipment
            {
                TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}",
                Origin = dto.Origin,
                Destination = dto.Destination,
                RecipientName = dto.RecipientName,
                CustomerId = dto.CustomerId,
                DispatcherId = userId,
                Status = ShipmentStatus.Pending,
                CreatedAt = DateTime.UtcNow,
                EstimatedDelivery = dto.EstimatedDelivery
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{shipment.Id}", new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status.ToString(),
                CreatedAt = shipment.CreatedAt,
                EstimatedDelivery = shipment.EstimatedDelivery,
                RecipientName = shipment.RecipientName,
                CustomerId = shipment.CustomerId
            });
        });

        group.MapPut("{id}/status", async (int id, StatusUpdateDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();
            if (!Enum.TryParse<ShipmentStatus>(dto.Status, out var newStatus))
                return Results.BadRequest("Invalid status");
            shipment.Status = newStatus;
            await db.SaveChangesAsync();
            return Results.Ok();
        });
    }
}

public record StatusUpdateDto(string Status);
```

