@code {
    [Parameter]
    public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool isSearching;
    private bool searched;
    private string lastSearched = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await SearchShipment();
        }
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await SearchShipment();
        }
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber)) return;

        isSearching = true;
        lastSearched = searchTrackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
        searched = true;
        isSearching = false;
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-warning text-dark",
        "PickedUp" => "bg-info text-dark",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-info",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out for Delivery",
        _ => status
    };

    private static string GetProgressBarClass(string status) => status switch
    {
        "Cancelled" => "bg-danger",
        "Delivered" => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(string status) => status switch
    {
        "Pending" => 10,
        "PickedUp" => 30,
        "InTransit" => 55,
        "OutForDelivery" => 80,
        "Delivered" => 100,
        "Cancelled" => 100,
        _ => 0
    };
}
```

